def string_to_md5(text):
    """
    Take an input 'text' and provide its md5 hash equivalent as an integer.
    If 'text' is None, a random string will be generated. 

    >>> string_to_md5('Hello world') == 1234567890
    """
    import hashlib

    if text is None:
        return hashlib.md5('RandomString'.encode()).hexdigest()
    return hashlib.md5(text.encode()).hexdigest().upper()
